mapper.select:
select

    transfer_type as transferType,
    agent_account as agentAccount,
    transfer_account as transferAccount,
    transfer_amount as transferAmount,
    order_no as orderNo,
    remark as remark,
    transfer_time as transferTime,
    transfer_status as transferStatus
    from agent_transfer_record
where 1 = 1

    AND transfer_type = #{vo.transferType}



        AND transfer_account = #{vo.agentAccount}




        AND agent_account = #{vo.agentAccount}




        AND transfer_account = #{vo.agentAccount}



    AND transfer_time  >=  #{vo.startTime}


    AND transfer_time  <=  #{vo.endTime}

order by transfer_time desc

select
    t.order_no as orderNo,
    t.agent_account as fromTransAccount,
    IF(t.agent_account = 'players', 0, (select t1.level from agent_info t1
    where t.agent_account = t1.agent_account and t1.site_code = #{vo.siteCode})) as fromTransLevel,
    t.transfer_account as toTransAccount,
    t.transfer_type as agentWalletType,
    t.transfer_status as orderStatus,
    t.transfer_amount as transferAmount,
    t.transfer_time as transferTime,
    t.remark as remark
from agent_transfer_record t
where site_code = #{vo.siteCode}

    AND t.order_no = #{vo.orderNo}


    AND t.agent_account = #{vo.fromAgentAccount}


    AND t.transfer_account = #{vo.toAgentAccount}


    AND t.transfer_type = #{vo.walletType}


    AND t.transfer_status = #{vo.orderStatus}


    AND t.transfer_amount  >=  #{vo.transferStartAmount}


    AND t.transfer_amount  <=  #{vo.transferEndAmount}


    AND t.transfer_time  >=  #{vo.startTime}


    AND t.transfer_time  <=  #{vo.endTime}




        ORDER BY transferAmount asc


        ORDER BY transferAmount desc



        ORDER BY transferTime asc


        ORDER BY transferTime desc



        order by t.transfer_time desc

select
count(1)
from agent_transfer_record t
where site_code = #{vo.siteCode}

    AND t.order_no = #{vo.orderNo}


    AND t.agent_account = #{vo.fromAgentAccount}


    AND t.transfer_account = #{vo.toAgentAccount}


    AND t.transfer_type = #{vo.walletType}


    AND t.transfer_status = #{vo.orderStatus}


    AND t.transfer_amount  >=  #{vo.transferStartAmount}


    AND t.transfer_amount  <=  #{vo.transferEndAmount}


    AND t.transfer_time  >=  #{vo.startTime}


    AND t.transfer_time  <=  #{vo.endTime}

select sum(transfer_amount) from agent_transfer_record
where  site_code = #{vo.siteCode}

    AND order_no = #{vo.orderNo}


    AND agent_account = #{vo.fromAgentAccount}


    AND transfer_account = #{vo.toAgentAccount}


    AND transfer_type = #{vo.walletType}


    AND transfer_status = #{vo.orderStatus}


    AND transfer_amount  >=  #{vo.transferStartAmount}


    AND transfer_amount  <=  #{vo.transferEndAmount}


    AND transfer_time  >=  #{vo.startTime}


    AND transfer_time  <=  #{vo.endTime}

select sum(transfer_amount) as amount
from agent_transfer_record s
         left join agent_info a on a.agent_account = s.agent_account
where s.transfer_time between #{beginTime} and #{endTime}
          and s.transfer_type=#{subordType}
          and a.agent_type in (1,2)

select s.agent_account
from agent_transfer_record s
         left join agent_info a on a.agent_account = s.agent_account
where s.transfer_time between #{beginTime} and #{endTime}
          and s.transfer_type=#{subordType}
          and a.agent_type in (1,2)

select
s.agent_account AS transferAccount,
s.transfer_account AS collectionAccount,
s.transfer_time AS distributeTime,
a.coin_from AS beforeDistributionAmount,
a.coin_to AS afterDistributionAmount,
a.coin_amount AS distributionAmount,
a.wallet_type AS walletType
from agent_transfer_record s
left join agent_coin_record a on a.order_no = s.order_no
and s.transfer_status = 0
and a.balance_type = #{vo.transferType}
and s.transfer_time  >=  #{vo.startTime}
and s.transfer_time  <=  #{vo.endTime}



        and s.transfer_account = #{vo.agentAccount}
        and s.agent_account != #{vo.agentAccount}

            and s.agent_account = #{vo.searchAccount}




        and s.agent_account = #{vo.agentAccount}
        and s.transfer_account != #{vo.agentAccount}

            and s.transfer_account = #{vo.searchAccount}


    and s.transfer_time  >=  #{vo.startTime}
    and s.transfer_time  <=  #{vo.endTime}

order by s.transfer_time desc
